sqlReaderQuery.value:
select t1.* from (select aaa.Id,aaa.AccountInfoId,aaa.MemberId,aaa.ClientId,aaa.ActionType,aaa.TrackedDate 
from @{pipeline().parameters.Schema_Name}.@{pipeline().parameters.Table_Name} aaa inner join dbo.AccountInfo a on (aaa.AccountInfoId=a.ID ) where a.Id in (@{join(pipeline().globalParameters.AccountID, ',')})

)t1
left join Temp_ActionTracking t2 on t1.Id = t2.ID
where t2.ID is null
